SELECT
FROM customer WHERE deleted = 0
AND company_name LIKE CONCAT('%', #{companyName}, '%')
AND industry = #{industry}
AND status = #{status}
ORDER BY created_at DESC

SELECT COUNT(*) > 0
FROM customer
WHERE company_name = #{companyName}
AND deleted = 0

    AND id != #{excludeId}

SELECT COUNT(*) > 0
FROM customer
WHERE business_license = #{businessLicense}
AND deleted = 0

    AND id != #{excludeId}

