UPDATE customer
SET deleted = 1,
    updated_at = NOW(),
    updated_by = #{updatedBy}
WHERE id = #{id}
AND deleted = 0

UPDATE customer
SET status = #{status},
    updated_at = NOW(),
    updated_by = #{updatedBy}
WHERE id = #{id}
AND deleted = 0
